+import type { ConfigurableTrait, Trait, TraitRecord } from '../trait/types';
+import type { World } from '../world';
+import { $aspect } from './symbols';
+import type { Aspect, AspectValue } from './types';
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return Boolean((value as Aspect | null | undefined)?.[$aspect]);
+}
+
+export function createAspect<T extends (Trait | Aspect)[]>(...inputs: T): Aspect<T> {
+    if (inputs.length < 2) throw new Error('Koota: an aspect requires at least two traits.');
+
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const fields = new Map<string, Trait>();
+    const schema: Record<string, unknown> = {};
+    for (const trait of traits) {
+        if (trait[$internal].relation || isRelation(trait as unknown)) {
+            throw new Error('Koota: relations cannot be aspect constituents.');
+        }
+        if (traits.indexOf(trait) !== traits.lastIndexOf(trait)) {
+            throw new Error('Koota: an aspect cannot contain the same trait more than once.');
+        }
+        if (typeof trait.schema !== 'object') continue;
+        for (const key of Object.keys(trait.schema)) {
+            if (fields.has(key)) throw new Error(`Koota: aspect field "${key}" is defined more than once.`);
+            fields.set(key, trait);
+            schema[key] = (trait.schema as Record<string, unknown>)[key];
+        }
+    }
+
+    const aspect = Object.assign(
+        (value?: AspectValue<T>) => [aspect, value] as [Aspect<T>, AspectValue<T>],
+        { id: aspectId++, traits: Object.freeze(traits.slice()), schema: Object.freeze(schema), [$aspect]: true }
+    ) as Aspect<T>;
+    return aspect;
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(world: World, entity: Entity, aspect: Aspect): Record<string, unknown> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    const result: Record<string, unknown> = {};
+    for (const trait of aspect.traits) Object.assign(result, getTrait(world, entity, trait) as TraitRecord<Trait>);
+    return result;
+}
+
+function valueForTrait(aspect: Aspect, trait: Trait, value: Record<string, unknown>) {
+    const result: Record<string, unknown> = {};
+    if (typeof trait.schema !== 'object') return result;
+    for (const key of Object.keys(trait.schema)) {
+        if (key in value) result[key] = value[key];
+    }
+    return result;
+}
+
+export function setAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown>) {
+    for (const trait of aspect.traits) {
+        const traitValue = valueForTrait(aspect, trait, value);
+        if (Object.keys(traitValue).length) setTrait(world, entity, trait, traitValue, true);
+    }
+}
+
+export function addAspect(world: World, entity: Entity, aspect: Aspect, value?: Record<string, unknown>) {
+    for (const trait of aspect.traits) {
+        if (hasTrait(world, entity, trait)) continue;
+        const traitValue = value ? valueForTrait(aspect, trait, value) : undefined;
+        addTrait(world, entity, traitValue && Object.keys(traitValue).length ? [trait, traitValue] : trait);
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect) {
+    removeTrait(world, entity, ...aspect.traits);
+}
